import sys, json, base64
data = json.load(sys.stdin)
content = base64.b64decode(data['content']).decode('utf-8')
nb = json.loads(content)
# Find cells with image outputs
for i, cell in enumerate(nb.get('cells', [])):
    for output in cell.get('outputs', []):
        if 'data' in output and 'image/png' in output['data']:
            print(f'Cell {i}: embedded image (base64)')
        elif 'data' in output and 'text/html' in output['data']:
            html = output['data']['text/html']
            if 'img' in html or 'src=' in html:
                print(f'Cell {i}: HTML with image reference')
                # Extract src
                import re
                srcs = re.findall(r'src=[\"']([^\"']+)', html if isinstance(html, str) else ''.join(html))
                for src in srcs:
                    print(f'  -> {src[:120]}')
" 2>/dev/null

