        "CV-深度学习笔记/02-深度学习理论-李沐/配置版本.md",
        "CV-深度学习笔记/03-深度学习课程-吴恩达/配置版本.md",
        "CV-深度学习笔记/04-大模型与Agent/配置版本.md",
    ],
}

# PyTorch基础 notebooks
PYTORCH_MAP = {
    "109_卷积原理.ipynb": [
        "CV-深度学习笔记/01-PyTorch基础-土堆/卷积原理.md"
    ],
    "111_最大池化层.ipynb": [
        "CV-深度学习笔记/01-PyTorch基础-土堆/最大池化层.md"
    ],
}

