    url = f"{API}/{REPO}/contents/{nb_name}"
    req = urllib.request.Request(url, headers={"Accept": "application/vnd.github.v3+json", "User-Agent": "Mozilla/5.0"})
    with urllib.request.urlopen(req) as resp:
        data = json.loads(resp.read())
    content = base64.b64decode(data['content']).decode('utf-8')
    return json.loads(content)

def extract_attachments(nb):
    images = {}
    for cell in nb.get('cells', []):
        if 'attachments' in cell:
            for fname, mime_dict in cell['attachments'].items():
                for mime, b64data in mime_dict.items():
                    images[fname] = (mime, b64data)
    return images

