    try:
        print(f"\nProcessing: {nb_name}")
        nb = fetch_notebook(nb_name)
        images = extract_attachments(nb)
        print(f"  Found {len(images)} embedded images")
        for fname, (mime, b64data) in images.items():
            # Determine extension
            ext = fname.split('.')[-1] if '.' in fname else 'png'
            out_path = os.path.join(VAULT, "assets", fname)
            img_bytes = base64.b64decode(b64data)
            with open(out_path, 'wb') as f:
                f.write(img_bytes)
            print(f"  Saved: {fname} ({len(img_bytes)} bytes)")
            total_extracted += 1
    except Exception as e:
        print(f"  ERROR: {e}")

print(f"\n=== Total extracted: {total_extracted} images ===")
